import json
import re

def extract_year(details):
    match = re.search(r'Published by.*?on.*?(\d{4})', details)
    if match:
        return int(match.group(1))
    match = re.search(r'released on.*?(\d{4})', details)
    if match:
        return int(match.group(1))
    return None

var_tool_query_db_63m5c8_response = var_tool_query_db_63m5c8_response['result']
var_tool_query_db_mI7f45_response = var_tool_query_db_mI7f45_response['result']


book_years = {}
for row in var_tool_query_db_63m5c8_response:
    book_id = row['book_id']
    details = row['details']
    year = extract_year(details)
    if year:
        book_years[book_id] = year

book_ratings = {}
for row in var_tool_query_db_mI7f45_response:
    purchase_id = row['purchase_id']
    book_id = purchase_id.replace('purchaseid_', 'bookid_')
    rating = float(row['rating'])
    if book_id in book_years:
        if book_id not in book_ratings:
            book_ratings[book_id] = []
        book_ratings[book_id].append(rating)

decade_ratings = {}
