    year = book_years[book_id]
    decade = (year // 10) * 10
    if decade not in decade_ratings:
        decade_ratings[decade] = {
            'ratings': [],
            'book_count': 0
        }
    decade_ratings[decade]['ratings'].extend(ratings)
    decade_ratings[decade]['book_count'] += 1


filtered_decades = {decade: data for decade, data in decade_ratings.items() if data['book_count'] >= 10}



for decade, data in filtered_decades.items():
    filtered_decades[decade]['avg_rating'] = sum(data['ratings']) / len(data['ratings'])


if filtered_decades:
    best_decade = max(filtered_decades, key=lambda decade: filtered_decades[decade]['avg_rating'])
    best_avg_rating = filtered_decades[best_decade]['avg_rating']

    print('__RESULT__:')
    print(json.dumps({'decade': best_decade, 'avg_rating': best_avg_rating}))
else:
    print('__RESULT__:')
    print(json.dumps(None))

